import { Component } from "react";
import "react-responsive-carousel/lib/styles/carousel.min.css"; // requires a loader
import { Carousel } from 'react-responsive-carousel';
import Proyecto from "./Proyecto";

const proyectos = [
    {img: null, enlace:'', nombre:'Mejora del algoritmo clásico: Quicksort', descripcion:'Mejora del algoritmo Quicksort usando el algoritmo de Inserción Directa para cubrir casos en los que la eficiencia del algoritmo normal se vea comprometida. Fue realizada como práctica para la asignatura: Análisis y Diseño de Algoritmos'},
    {img: null, enlace:'', nombre:'UVash', descripcion:''},
]

class MiSlider extends Component {
    render(){
        return (
            <div>
                <Carousel showArrows={true} axis="vertical" autoPlay={true} dynamicHeight={true} interval={8000} infiniteLoop={true}>
                    {proyectos.map(x =>
                        <Proyecto img={x.img} enlace={x.enlace} nombre={x.nombre} descripcion={x.descripcion} />
                    )}
                </Carousel>
            </div>
        )
    }
}

export default MiSlider
